#include <stdio.h>
#include <stdlib.h>

typedef struct MedianFinder {
    int* nums;
    int size;
    int capacity;
} MedianFinder;

MedianFinder* medianFinderCreate() {
    MedianFinder* obj = (MedianFinder*) malloc(sizeof(MedianFinder));
    obj->nums = (int*) malloc(sizeof(int) * 100000);
    obj->size = 0;
    obj->capacity = 100000;
    return obj;
}

void medianFinderAddNum(MedianFinder* obj, int num) {
    obj->nums[obj->size++] = num;
}

double medianFinderFindMedian(MedianFinder* obj) {
    int n = obj->size;
    int* nums = obj->nums;
    for (int i = 0; i < n - 1; i++) {
        for (int j = 0; j < n - i - 1; j++) {
            if (nums[j] > nums[j + 1]) {
                int temp = nums[j];
                nums[j] = nums[j + 1];
                nums[j + 1] = temp;
            }
        }
    }
    if (n % 2 == 1) {
        return (double) nums[n / 2];
    } else {
        return (double) (nums[n / 2 - 1] + nums[n / 2]) / 2;
    }
}

