class MedianFinder {
    constructor() {
        // Initialize an empty array to store numbers
        this.nums = [];
    }

    // Function to add a number
    addNum(num) {
        // Push the number into the array
        this.nums.push(num);
    }

    // Function to find the median
    findMedian() {
        // Sort the array
        this.nums.sort((a, b) => a - b);

        // Get length of array
        const n = this.nums.length;

        // If odd length, return middle element
        if (n % 2 === 1) {
            return this.nums[Math.floor(n / 2)];
        }

        // If even, return average of two middle elements
        return (this.nums[n / 2 - 1] + this.nums[n / 2]) / 2.0;
    }
}
